/// Represents an offline data entry with a unique identifier.
class OfflineDataEntry {
  final String id;
  final String title;
  final String content;
  final DateTime createdAt;
  final bool isSynced;
  final String idType;

  OfflineDataEntry({
    required this.id,
    required this.title,
    required this.content,
    required this.createdAt,
    this.isSynced = false,
    required this.idType,
  });

  OfflineDataEntry copyWith({bool? isSynced}) {
    return OfflineDataEntry(
      id: id,
      title: title,
      content: content,
      createdAt: createdAt,
      isSynced: isSynced ?? this.isSynced,
      idType: idType,
    );
  }

  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'title': title,
      'content': content,
      'createdAt': createdAt.toIso8601String(),
      'isSynced': isSynced,
      'idType': idType,
    };
  }
}

