class HomeScreen extends StatefulWidget {
  const HomeScreen({super.key});

  @override
  State<HomeScreen> createState() => _HomeScreenState();
}

enum UUIDType { v4, timeBased, compact, shortId }

class _HomeScreenState extends State<HomeScreen> with SingleTickerProviderStateMixin {
  late TabController _tabController;
  final List<OfflineDataEntry> _entries = [];
  final List<Map<String, String>> _generatedIds = [];
  UUIDType _selectedType = UUIDType.v4;

  @override
  void initState() {
    super.initState();
    _tabController = TabController(length: 2, vsync: this);
  }

  @override
  void dispose() {
    _tabController.dispose();
    super.dispose();
  }

  String _generateId() {
    switch (_selectedType) {
      case UUIDType.v4:
        return SecureUUIDGenerator.generateV4();
      case UUIDType.timeBased:
        return SecureUUIDGenerator.generateTimeBased();
      case UUIDType.compact:
        return SecureUUIDGenerator.generateCompact();
      case UUIDType.shortId:
        return SecureUUIDGenerator.generateShortId();
    }
  }

  String _typeLabel(UUIDType type) {
    switch (type) {
      case UUIDType.v4:
        return 'UUID v4';
      case UUIDType.timeBased:
        return 'Time-Based';
      case UUIDType.compact:
        return 'Compact';
      case UUIDType.shortId:
        return 'Short ID';
    }
  }

  void _generateAndShowId() {
    final id = _generateId();
    final label = _typeLabel(_selectedType);
    setState(() {
      _generatedIds.insert(0, {'id': id, 'type': label});
    });
  }

  void _generateBatch(int count) {
    final label = _typeLabel(_selectedType);
    final List<Map<String, String>> batch = [];
    for (int i = 0; i < count; i++) {
      batch.add({'id': _generateId(), 'type': label});
    }
    setState(() {
      _generatedIds.insertAll(0, batch);
    });
  }

  void _copyToClipboard(String text) {
    Clipboard.setData(ClipboardData(text: text));
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Text('Copied: $text'),
        duration: const Duration(seconds: 1),
        behavior: SnackBarBehavior.floating,
      ),
    );
  }

  void _showCreateEntryDialog() {
