            FilledButton(
              onPressed: () {
                if (titleController.text.isNotEmpty) {
                  final entry = OfflineDataEntry(
                    id: _generateId(),
                    title: titleController.text,
                    content: contentController.text,
                    createdAt: DateTime.now(),
                    idType: _typeLabel(_selectedType),
                  );
                  setState(() {
                    _entries.insert(0, entry);
                  });
                  Navigator.pop(context);
                  ScaffoldMessenger.of(context).showSnackBar(
                    SnackBar(
                      content: Text('Entry created with ID: ${entry.id}'),
                      behavior: SnackBarBehavior.floating,
                    ),
                  );
                }
              },
              child: const Text('Create'),
            ),
          ],
        );
      },
    );
  }

  void _simulateSync() {
    setState(() {
      for (int i = 0; i < _entries.length; i++) {
        if (!_entries[i].isSynced) {
          _entries[i] = _entries[i].copyWith(isSynced: true);
        }
      }
    });
    ScaffoldMessenger.of(context).showSnackBar(
      const SnackBar(
        content: Text('All entries synced successfully!'),
        behavior: SnackBarBehavior.floating,
      ),
    );
  }

  void _testUniqueness() {
    const int testCount = 10000;
    final Set<String> ids = {};
    final stopwatch = Stopwatch()..start();

    for (int i = 0; i < testCount; i++) {
