  }

  String _typeDescription(UUIDType type) {
    switch (type) {
      case UUIDType.v4:
        return 'Standard RFC 4122 UUID v4 — 128-bit random, universally unique. '
            'Uses Random.secure() (CSPRNG) for cryptographic-grade randomness.';
      case UUIDType.timeBased:
        return 'Timestamp-prefixed UUID — first 48 bits encode creation time for '
            'natural sort ordering. Remaining bits are cryptographically random.';
      case UUIDType.compact:
        return 'Compact 32-character hex string — same entropy as UUID v4 but '
            'without hyphens. Useful for database keys and URLs.';
      case UUIDType.shortId:
        return 'Short 12-character alphanumeric ID — uses base-62 encoding for '
            'human-friendly display. ~71 bits of entropy.';
    }
  }
